38	/**
39	 * {@link Condition} that checks for the presence or absence of
40	 * {@link WebApplicationContext}.
41	 *
42	 * @author Dave Syer
43	 * @author Phillip Webb
44	 * @see ConditionalOnWebApplication
45	 * @see ConditionalOnNotWebApplication
46	 */
47	@Order(Ordered.HIGHEST_PRECEDENCE + 20)
48	class OnWebApplicationCondition extends FilteringSpringBootCondition {
49	
50		private static final String SERVLET_WEB_APPLICATION_CLASS = "org.springframework.web.context.support.GenericWebApplicationContext";
51	
52		private static final String REACTIVE_WEB_APPLICATION_CLASS = "org.springframework.web.reactive.HandlerResult";
53	
54		@Override
55		protected @Nullable ConditionOutcome[] getOutcomes(@Nullable String[] autoConfigurationClasses,
56				AutoConfigurationMetadata autoConfigurationMetadata) {
57			@Nullable ConditionOutcome[] outcomes = new ConditionOutcome[autoConfigurationClasses.length];
58			for (int i = 0; i < outcomes.length; i++) {
59				String autoConfigurationClass = autoConfigurationClasses[i];
60				if (autoConfigurationClass != null) {
61					outcomes[i] = getOutcome(
62							autoConfigurationMetadata.get(autoConfigurationClass, "ConditionalOnWebApplication"));
63				}
64			}
65			return outcomes;
66		}
67	
68		private @Nullable ConditionOutcome getOutcome(@Nullable String type) {
69			if (type == null) {
70				return null;
71			}
72			ConditionMessage.Builder message = ConditionMessage.forCondition(ConditionalOnWebApplication.class);
73			ClassNameFilter missingClassFilter = ClassNameFilter.MISSING;
74			if (ConditionalOnWebApplication.Type.SERVLET.name().equals(type)) {
75				if (missingClassFilter.matches(SERVLET_WEB_APPLICATION_CLASS, getBeanClassLoader())) {
76					return ConditionOutcome.noMatch(message.didNotFind("servlet web application classes").atAll());
77				}
78			}
79			if (ConditionalOnWebApplication.Type.REACTIVE.name().equals(type)) {
80				if (missingClassFilter.matches(REACTIVE_WEB_APPLICATION_CLASS, getBeanClassLoader())) {
81					return ConditionOutcome.noMatch(message.didNotFind("reactive web application classes").atAll());
82				}
83			}
84			if (missingClassFilter.matches(SERVLET_WEB_APPLICATION_CLASS, getBeanClassLoader())
85					&& !ClassUtils.isPresent(REACTIVE_WEB_APPLICATION_CLASS, getBeanClassLoader())) {
86				return ConditionOutcome.noMatch(message.didNotFind("reactive or servlet web application classes").atAll());
87			}
88			return null;
89		}
90	
91		@Override
92		public ConditionOutcome getMatchOutcome(ConditionContext context, AnnotatedTypeMetadata metadata) {
93			boolean required = metadata.isAnnotated(ConditionalOnWebApplication.class.getName());
94			ConditionOutcome outcome = isWebApplication(context, metadata, required);
95			if (required && !outcome.isMatch()) {
96				return ConditionOutcome.noMatch(outcome.getConditionMessage());
97			}
98			if (!required && outcome.isMatch()) {
99				return ConditionOutcome.noMatch(outcome.getConditionMessage());
100			}
101			return ConditionOutcome.match(outcome.getConditionMessage());
102		}
103	
104		private ConditionOutcome isWebApplication(ConditionContext context, AnnotatedTypeMetadata metadata,
105				boolean required) {
106			return switch (deduceType(metadata)) {
107				case SERVLET -> isServletWebApplication(context);
108				case REACTIVE -> isReactiveWebApplication(context);
109				default -> isAnyWebApplication(context, required);
110			};
111		}
112	
113		private ConditionOutcome isAnyWebApplication(ConditionContext context, boolean required) {
114			ConditionMessage.Builder message = ConditionMessage.forCondition(ConditionalOnWebApplication.class,
115					required ? "(required)" : "");
116			ConditionOutcome servletOutcome = isServletWebApplication(context);
117			if (servletOutcome.isMatch() && required) {
118				return new ConditionOutcome(servletOutcome.isMatch(), message.because(servletOutcome.getMessage()));
119			}
120			ConditionOutcome reactiveOutcome = isReactiveWebApplication(context);
121			if (reactiveOutcome.isMatch() && required) {
122				return new ConditionOutcome(reactiveOutcome.isMatch(), message.because(reactiveOutcome.getMessage()));
123			}
124			return new ConditionOutcome(servletOutcome.isMatch() || reactiveOutcome.isMatch(),
125					message.because(servletOutcome.getMessage()).append("and").append(reactiveOutcome.getMessage()));
126		}
127	
128		private ConditionOutcome isServletWebApplication(ConditionContext context) {
129			ConditionMessage.Builder message = ConditionMessage.forCondition("");
130			if (ClassNameFilter.MISSING.matches(SERVLET_WEB_APPLICATION_CLASS, context.getClassLoader())) {
131				return ConditionOutcome.noMatch(message.didNotFind("servlet web application classes").atAll());
132			}
133			if (context.getBeanFactory() != null) {
134				String[] scopes = context.getBeanFactory().getRegisteredScopeNames();
135				if (ObjectUtils.containsElement(scopes, "session")) {
136					return ConditionOutcome.match(message.foundExactly("'session' scope"));
137				}
138			}
139			if (context.getEnvironment() instanceof ConfigurableWebEnvironment) {
140				return ConditionOutcome.match(message.foundExactly("ConfigurableWebEnvironment"));
141			}
142			if (context.getResourceLoader() instanceof WebApplicationContext) {
143				return ConditionOutcome.match(message.foundExactly("WebApplicationContext"));
144			}
145			return ConditionOutcome.noMatch(message.because("not a servlet web application"));
146		}
147	
148		private ConditionOutcome isReactiveWebApplication(ConditionContext context) {
149			ConditionMessage.Builder message = ConditionMessage.forCondition("");
150			if (ClassNameFilter.MISSING.matches(REACTIVE_WEB_APPLICATION_CLASS, context.getClassLoader())) {
151				return ConditionOutcome.noMatch(message.didNotFind("reactive web application classes").atAll());
152			}
153			if (context.getEnvironment() instanceof ConfigurableReactiveWebEnvironment) {
154				return ConditionOutcome.match(message.foundExactly("ConfigurableReactiveWebEnvironment"));
155			}
156			if (context.getResourceLoader() instanceof ReactiveWebApplicationContext) {
157				return ConditionOutcome.match(message.foundExactly("ReactiveWebApplicationContext"));
158			}
159			return ConditionOutcome.noMatch(message.because("not a reactive web application"));
160		}
161	
162		private Type deduceType(AnnotatedTypeMetadata metadata) {
163			Map<String, @Nullable Object> attributes = metadata
164				.getAnnotationAttributes(ConditionalOnWebApplication.class.getName());
165			if (attributes != null) {
166				Object type = attributes.get("type");
167				Assert.state(type != null, "'type' must not be null");
168				return (Type) type;
169			}
170			return Type.ANY;
171		}
