400				long startTime = System.nanoTime();
401				@Nullable String[] candidates = StringUtils.toStringArray(configurations);
402				boolean skipped = false;
403				for (AutoConfigurationImportFilter filter : this.filters) {
404					boolean[] match = filter.match(candidates, this.autoConfigurationMetadata);
405					for (int i = 0; i < match.length; i++) {
406						if (!match[i]) {
407							candidates[i] = null;
408							skipped = true;
