29	import org.springframework.util.StringUtils;
30	
31	/**
32	 * Base of all {@link Condition} implementations used with Spring Boot. Provides sensible
33	 * logging to help the user diagnose what classes are loaded.
34	 *
35	 * @author Phillip Webb
36	 * @author Greg Turnquist
37	 * @since 1.0.0
38	 */
39	public abstract class SpringBootCondition implements Condition {
40	
41		private final Log logger = LogFactory.getLog(getClass());
42	
43		@Override
44		public final boolean matches(ConditionContext context, AnnotatedTypeMetadata metadata) {
45			String classOrMethodName = getClassOrMethodName(metadata);
46			try {
47				ConditionOutcome outcome = getMatchOutcome(context, metadata);
48				logOutcome(classOrMethodName, outcome);
49				recordEvaluation(context, classOrMethodName, outcome);
50				return outcome.isMatch();
51			}
52			catch (NoClassDefFoundError ex) {
53				throw new IllegalStateException("Could not evaluate condition on " + classOrMethodName + " due to "
54						+ ex.getMessage() + " not found. Make sure your own configuration does not rely on "
55						+ "that class. This can also happen if you are "
56						+ "@ComponentScanning a springframework package (e.g. if you "
57						+ "put a @ComponentScan in the default package by mistake)", ex);
58			}
59			catch (RuntimeException ex) {
60				throw new IllegalStateException("Error processing condition on " + getName(metadata), ex);
61			}
62		}
63	
64		private String getName(AnnotatedTypeMetadata metadata) {
65			if (metadata instanceof AnnotationMetadata annotationMetadata) {
66				return annotationMetadata.getClassName();
67			}
68			if (metadata instanceof MethodMetadata methodMetadata) {
69				return methodMetadata.getDeclaringClassName() + "." + methodMetadata.getMethodName();
70			}
71			return metadata.toString();
72		}
73	
74		private static String getClassOrMethodName(AnnotatedTypeMetadata metadata) {
75			if (metadata instanceof ClassMetadata classMetadata) {
76				return classMetadata.getClassName();
77			}
78			MethodMetadata methodMetadata = (MethodMetadata) metadata;
79			return methodMetadata.getDeclaringClassName() + "#" + methodMetadata.getMethodName();
80		}
81	
82		protected final void logOutcome(String classOrMethodName, ConditionOutcome outcome) {
83			if (this.logger.isTraceEnabled()) {
84				this.logger.trace(getLogMessage(classOrMethodName, outcome));
85			}
86		}
87	
88		private StringBuilder getLogMessage(String classOrMethodName, ConditionOutcome outcome) {
89			StringBuilder message = new StringBuilder();
90			message.append("Condition ");
91			message.append(ClassUtils.getShortName(getClass()));
92			message.append(" on ");
93			message.append(classOrMethodName);
94			message.append(outcome.isMatch() ? " matched" : " did not match");
95			if (StringUtils.hasLength(outcome.getMessage())) {
96				message.append(" due to ");
97				message.append(outcome.getMessage());
98			}
99			return message;
100		}
101	
102		private void recordEvaluation(ConditionContext context, String classOrMethodName, ConditionOutcome outcome) {
103			if (context.getBeanFactory() != null) {
104				ConditionEvaluationReport.get(context.getBeanFactory())
105					.recordConditionEvaluation(classOrMethodName, this, outcome);
106			}
107		}
108	
109		/**
110		 * Determine the outcome of the match along with suitable log output.
111		 * @param context the condition context
112		 * @param metadata the annotation metadata
113		 * @return the condition outcome
114		 */
115		public abstract ConditionOutcome getMatchOutcome(ConditionContext context, AnnotatedTypeMetadata metadata);
116	
117		/**
118		 * Return true if any of the specified conditions match.
119		 * @param context the context
120		 * @param metadata the annotation meta-data
121		 * @param conditions conditions to test
122		 * @return {@code true} if any condition matches.
123		 */
124		protected final boolean anyMatches(ConditionContext context, AnnotatedTypeMetadata metadata,
125				Condition... conditions) {
126			for (Condition condition : conditions) {
127				if (matches(context, metadata, condition)) {
128					return true;
129				}
130			}
131			return false;
132		}
133	
134		/**
135		 * Return true if any of the specified condition matches.
136		 * @param context the context
137		 * @param metadata the annotation meta-data
138		 * @param condition condition to test
139		 * @return {@code true} if the condition matches.
140		 */
141		protected final boolean matches(ConditionContext context, AnnotatedTypeMetadata metadata, Condition condition) {
142			if (condition instanceof SpringBootCondition springBootCondition) {
143				return springBootCondition.getMatchOutcome(context, metadata).isMatch();
144			}
145			return condition.matches(context, metadata);
146		}
147	
148	}
